function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }

	//Template Designer Permissions Administrator
	g_form.showFieldMsg("can_manage_process_permissions", 
						getMessage("Tasker - Manage template permissions for Personal, OU, and Global template designers."),
						"info");


}
